import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.BtjAF3GT.js";const p=JSON.parse('{"title":"User Guide","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide.md","filePath":"user-guide.md","lastUpdated":1775380787000}'),r={name:"user-guide.md"};function s(l,e,n,u,d,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="user-guide" tabindex="-1">User Guide <a class="header-anchor" href="#user-guide" aria-label="Permalink to &quot;User Guide&quot;">​</a></h1><p>Use this guide when you are getting started as an end user. It follows the real product flow: sign in, route work, execute prompts, review outcomes, and then expand into team and workspace features.</p><h2 id="start-with-the-core-loop" tabindex="-1">Start with the core loop <a class="header-anchor" href="#start-with-the-core-loop" aria-label="Permalink to &quot;Start with the core loop&quot;">​</a></h2><p>CS Code Router is built around one operating loop:</p><ol><li>write or paste a prompt</li><li>preview the route decision</li><li>execute against the selected model path</li><li>review the outcome and leave feedback</li><li>continue the conversation without losing context</li></ol><h2 id="your-first-session" tabindex="-1">Your first session <a class="header-anchor" href="#your-first-session" aria-label="Permalink to &quot;Your first session&quot;">​</a></h2><h3 id="step-1-sign-in" tabindex="-1">Step 1: Sign in <a class="header-anchor" href="#step-1-sign-in" aria-label="Permalink to &quot;Step 1: Sign in&quot;">​</a></h3><p>Most users sign in through the web app with email and password.</p><p>If your organization has single sign-on enabled, you may see an SSO flow instead.</p><h3 id="step-2-open-studio" tabindex="-1">Step 2: Open Studio <a class="header-anchor" href="#step-2-open-studio" aria-label="Permalink to &quot;Step 2: Open Studio&quot;">​</a></h3><p>Studio is the main workspace for prompt routing and execution.</p><p>In Studio you can:</p><ul><li>draft prompts</li><li>preview routing decisions before spending provider tokens</li><li>execute directly when the route looks correct</li><li>switch models without losing conversation continuity</li><li>leave feedback on completed outcomes</li></ul><h3 id="step-3-review-the-route" tabindex="-1">Step 3: Review the route <a class="header-anchor" href="#step-3-review-the-route" aria-label="Permalink to &quot;Step 3: Review the route&quot;">​</a></h3><p>Use route preview when you want to understand why a provider or model was selected before execution.</p><p>This is the fastest way to confirm:</p><ul><li>the expected model path</li><li>fallback behavior</li><li>budget or policy effects</li><li>local versus cloud routing choices</li></ul><h3 id="step-4-execute-and-continue-the-thread" tabindex="-1">Step 4: Execute and continue the thread <a class="header-anchor" href="#step-4-execute-and-continue-the-thread" aria-label="Permalink to &quot;Step 4: Execute and continue the thread&quot;">​</a></h3><p>Once the route looks right, execute the request.</p><p>Conversations are stored server-side per user and tenant, which means:</p><ul><li>model switches do not break the thread</li><li>older sessions can be resumed later</li><li>recent turns and memory can be reused</li><li>optimization feedback stays attached to completed work</li></ul><h2 id="other-product-areas" tabindex="-1">Other product areas <a class="header-anchor" href="#other-product-areas" aria-label="Permalink to &quot;Other product areas&quot;">​</a></h2><h3 id="teams" tabindex="-1">Teams <a class="header-anchor" href="#teams" aria-label="Permalink to &quot;Teams&quot;">​</a></h3><p>Use Teams to manage members, invites, and shared ownership.</p><h3 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h3><p>Use Billing to review plan status, invoice items, allowance usage, and export flows.</p><h3 id="policies-and-activity" tabindex="-1">Policies and activity <a class="header-anchor" href="#policies-and-activity" aria-label="Permalink to &quot;Policies and activity&quot;">​</a></h3><p>Some workspaces call this section <code>Ops</code>. It is where you manage routing policies, alerts, webhooks, retries, and recent workspace activity.</p><h2 id="terminal-workflows" tabindex="-1">Terminal workflows <a class="header-anchor" href="#terminal-workflows" aria-label="Permalink to &quot;Terminal workflows&quot;">​</a></h2><p>Humans usually authenticate with:</p><ul><li>email and password in the web app</li><li>browser OAuth in the CLI</li></ul><p>Automation usually authenticates with:</p><ul><li>scoped API keys</li></ul><p>Common terminal workflows:</p><ul><li>use <code>cs-code route</code> to inspect routing before execution</li><li>use <code>cs-code execute</code> when the request is ready to run</li><li>use <code>cs-code agent</code> for supported text and coding workflows</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./workspace-reference">workspace-reference.md</a> for the full UI surface map</li><li><a href="./cli-reference">cli-reference.md</a> for terminal-first usage</li><li><a href="./model-routing">model-routing.md</a> for routing logic and fallbacks</li><li><a href="./security-features">security-features.md</a> for auth, protection, and audit controls</li><li><a href="./api-reference">api-reference.md</a> when you want to automate against the platform directly</li></ul>',37)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
